public int[] tenRun(int[] nums) {
    boolean inMultipleOf10Sequence = false;
    int multipleOf10 = 0;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] % 10 == 0) {
            inMultipleOf10Sequence = true;
            multipleOf10 = nums[i];
        } else if (inMultipleOf10Sequence) {
            nums[i] = multipleOf10;
        }
    }

    return nums;
}

